<script>
  import { onDestroy, onMount } from 'svelte'
  import { PDFDocument, StandardFonts, rgb } from 'pdf-lib'
  import { translations, availableLanguages } from './translations.js'

  const countries = [['ES', 'España'], ['PT', 'Portugal'], ['FR', 'France'], ['US', 'United States'], ['GB', 'United Kingdom'], ['DE', 'Deutschland'], ['IT', 'Italia']]
  const regions = {
    ES: [['', 'Todo el país'], ['ES-AN', 'Andalucía'], ['ES-CT', 'Cataluña'], ['ES-EX', 'Extremadura'], ['ES-GA', 'Galicia'], ['ES-MD', 'Madrid'], ['ES-PV', 'País Vasco'], ['ES-VC', 'Comunidad Valenciana']],
    US: [['', 'Whole country'], ['US-CA', 'California'], ['US-FL', 'Florida'], ['US-NY', 'New York'], ['US-TX', 'Texas']]
  }

  let language = 'es'
  let theme = 'light'
  let menuOpen = false
  let stepIndex = 0
  let startMonth = new Date().getMonth()
  let startYear = new Date().getFullYear()
  let totalMonths = 12
  let monthsPerPage = 2
  let monthColumns = 'auto'
  let pageSize = 'A4'
  let orientation = 'landscape'
  let showHolidays = true
  let country = 'ES'
  let region = 'ES-EX'
  let shadeWeekends = true
  let showWeekNumbers = false
  let showEmptyDays = false
  let showNotes = false
  let daySize = 'comfortable'
  let colorMode = 'color'
  let roundedCells = true
  let includeFooter = true
  let pdfUrl = ''
  let isGenerating = false
  let message = ''

  $: t = translations[language] || translations.es
  $: steps = t.steps.map(([key, title, help]) => ({ key, title, help }))
  $: currentStep = steps[stepIndex]
  $: monthNames = t.months
  $: weekNames = t.week
  $: availableRegions = regions[country] || [['', t.labels.auto]]
  $: if (!availableRegions.some(([code]) => code === region)) region = ''
  $: calendarMonths = Array.from({ length: Number(totalMonths) }, (_, index) => addMonths(Number(startYear), Number(startMonth), index))
  $: computedColumns = getColumnCount(Number(monthsPerPage))
  $: selectedSummary = [
    [t.summary.start, `${monthNames[startMonth]} ${startYear}`],
    [t.summary.duration, `${totalMonths} ${Number(totalMonths) === 1 ? t.summary.month : t.summary.months}`],
    [t.summary.page, `${pageSize}, ${orientation === 'landscape' ? t.labels.landscape : t.labels.portrait}, ${monthsPerPage} ${t.summary.perPage}, ${computedColumns} ${computedColumns === 1 ? t.summary.column : t.summary.columns}`],
    [t.summary.content, contentSummary()],
    [t.summary.style, `${daySizeLabel(daySize)}, ${colorMode === 'color' ? t.labels.color : t.labels.grayscale}`]
  ]

  onMount(() => {
    const pathLang = window.location.pathname.split('/').filter(Boolean)[0]
    const queryLang = new URLSearchParams(window.location.search).get('lang')
    const storedLang = localStorage.getItem('printacalendar-language')
    const candidate = [pathLang, queryLang, storedLang].find((code) => availableLanguages.some(([lang]) => lang === code))
    if (candidate) language = candidate
    document.documentElement.lang = language

    const storedTheme = localStorage.getItem('printacalendar-theme') || localStorage.getItem('alon-tools-theme') || localStorage.getItem('theme')
    theme = storedTheme || (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light')
    document.documentElement.dataset.theme = theme

    const onKeydown = (event) => { if (event.key === 'Escape') menuOpen = false }
    const mediaQuery = window.matchMedia('(min-width: 981px)')
    const onMediaChange = (event) => { if (event.matches) menuOpen = false }
    document.addEventListener('keydown', onKeydown)
    mediaQuery.addEventListener('change', onMediaChange)
    return () => { document.removeEventListener('keydown', onKeydown); mediaQuery.removeEventListener('change', onMediaChange) }
  })

  onDestroy(() => revokePdf())

  function languageUrl(code) { return `/${code}/` }
  function toggleTheme() { theme = theme === 'dark' ? 'light' : 'dark'; document.documentElement.dataset.theme = theme; localStorage.setItem('printacalendar-theme', theme); localStorage.setItem('alon-tools-theme', theme); localStorage.setItem('theme', theme) }
  function rememberLanguage(code) { localStorage.setItem('printacalendar-language', code) }
  function nextStep() { stepIndex = Math.min(stepIndex + 1, steps.length - 1) }
  function previousStep() { stepIndex = Math.max(stepIndex - 1, 0) }
  function goToStep(index) { stepIndex = index; menuOpen = false }
  function addMonths(year, month, amount) { const date = new Date(year, month + amount, 1); return { year: date.getFullYear(), month: date.getMonth() } }
  function getColumnCount(perPage) { if (monthColumns !== 'auto') return Math.min(Number(monthColumns), perPage); if (perPage === 1) return 1; if (perPage === 2) return orientation === 'landscape' ? 2 : 1; if (perPage === 3) return orientation === 'landscape' ? 3 : 1; if (perPage === 4) return 2; return orientation === 'landscape' ? 3 : 2 }
  function daysForMonth(year, month) { const first = new Date(year, month, 1); const offset = (first.getDay() + 6) % 7; const days = new Date(year, month + 1, 0).getDate(); const previousDays = new Date(year, month, 0).getDate(); const cells = []; for (let i = 0; i < offset; i += 1) cells.push({ day: previousDays - offset + i + 1, muted: true, weekend: i >= 5 }); for (let day = 1; day <= days; day += 1) { const weekday = (new Date(year, month, day).getDay() + 6) % 7; cells.push({ day, muted: false, weekend: weekday >= 5 }) } while (cells.length % 7 !== 0 || cells.length < 35) { const day = cells.length - offset - days + 1; const weekday = (new Date(year, month + 1, day).getDay() + 6) % 7; cells.push({ day, muted: true, weekend: weekday >= 5 }) } return showEmptyDays ? cells : cells.map((cell) => cell.muted ? { ...cell, day: '' } : cell) }
  function daySizeLabel(value) { return value === 'large' ? t.labels.large : value === 'compact' ? t.labels.compact : t.labels.comfortable }
  function contentSummary() { const items = []; if (showHolidays) items.push(`${t.labels.holidays}: ${country}${region ? ` / ${region}` : ''}`); if (shadeWeekends) items.push(t.labels.weekends); if (showWeekNumbers) items.push(t.labels.weekNumbers); if (showNotes) items.push(t.labels.notes); return items.length ? items.join(', ') : '-' }
  function pageDimensions() { const sizes = { A4: [595.28, 841.89], A3: [841.89, 1190.55], Letter: [612, 792] }; let [width, height] = sizes[pageSize] || sizes.A4; if (orientation === 'landscape') [width, height] = width > height ? [width, height] : [height, width]; if (orientation === 'portrait') [width, height] = width < height ? [width, height] : [height, width]; return [width, height] }
  async function generatePdf() { isGenerating = true; message = ''; revokePdf(); try { const pdf = await PDFDocument.create(); const font = await pdf.embedFont(StandardFonts.Helvetica); const bold = await pdf.embedFont(StandardFonts.HelveticaBold); const [width, height] = pageDimensions(); const perPage = Number(monthsPerPage); const primary = colorMode === 'color' ? rgb(0.94, 0.32, 0.24) : rgb(0.1, 0.1, 0.1); const soft = colorMode === 'color' ? rgb(1, 0.95, 0.93) : rgb(0.94, 0.94, 0.94); const weekend = colorMode === 'color' ? rgb(1, 0.92, 0.86) : rgb(0.9, 0.9, 0.9); for (let i = 0; i < calendarMonths.length; i += perPage) { const page = pdf.addPage([width, height]); const slice = calendarMonths.slice(i, i + perPage); const cols = getColumnCount(perPage); const rows = Math.ceil(slice.length / cols); const gap = 18; const margin = 36; const footerSpace = includeFooter ? 22 : 0; const blockWidth = (width - margin * 2 - gap * (cols - 1)) / cols; const blockHeight = (height - margin * 2 - footerSpace - gap * (rows - 1)) / rows; slice.forEach((item, index) => { const col = index % cols; const row = Math.floor(index / cols); const x = margin + col * (blockWidth + gap); const y = height - margin - (row + 1) * blockHeight - row * gap; drawMonth(page, { ...item, x, y, w: blockWidth, h: blockHeight, font, bold, primary, soft, weekend }) }); if (includeFooter) page.drawText(t.source, { x: margin, y: 18, size: 9, font, color: rgb(0.4, 0.45, 0.52) }) } const bytes = await pdf.save(); pdfUrl = URL.createObjectURL(new Blob([bytes], { type: 'application/pdf' })); message = t.ok; stepIndex = steps.length - 1 } catch (error) { message = t.error; console.error(error) } finally { isGenerating = false } }
  function drawMonth(page, data) { const { year, month, x, y, w, h, font, bold, primary, soft, weekend } = data; const title = `${monthNames[month]} ${year}`; page.drawRectangle({ x, y, width: w, height: h, color: rgb(1, 1, 1), borderColor: rgb(0.86, 0.88, 0.92), borderWidth: 1 }); page.drawRectangle({ x, y: y + h - 34, width: w, height: 34, color: soft }); page.drawText(title.charAt(0).toUpperCase() + title.slice(1), { x: x + 12, y: y + h - 23, size: daySize === 'large' ? 18 : 15, font: bold, color: primary }); const top = y + h - 56; const cellW = w / 7; const cellH = Math.max(16, (h - 72 - (showNotes ? 34 : 0)) / 7); weekNames.forEach((name, index) => page.drawText(name, { x: x + index * cellW + 8, y: top, size: 9, font: bold, color: rgb(0.35, 0.39, 0.46) })); daysForMonth(year, month).slice(0, 42).forEach((cell, index) => { const col = index % 7; const row = Math.floor(index / 7); const cx = x + col * cellW; const cy = top - 12 - (row + 1) * cellH; if (shadeWeekends && cell.weekend && !cell.muted) page.drawRectangle({ x: cx + 2, y: cy + 2, width: cellW - 4, height: cellH - 4, color: weekend }); page.drawRectangle({ x: cx, y: cy, width: cellW, height: cellH, borderColor: rgb(0.88, 0.9, 0.93), borderWidth: 0.5 }); if (cell.day) page.drawText(String(cell.day), { x: cx + 6, y: cy + cellH - 14, size: daySize === 'large' ? 12 : daySize === 'compact' ? 8 : 10, font, color: cell.muted ? rgb(0.65, 0.68, 0.72) : rgb(0.08, 0.1, 0.14) }) }); if (showNotes) { page.drawText(t.notes, { x: x + 10, y: y + 20, size: 9, font: bold, color: rgb(0.4, 0.45, 0.52) }); page.drawLine({ start: { x: x + 48, y: y + 22 }, end: { x: x + w - 10, y: y + 22 }, thickness: 0.5, color: rgb(0.82, 0.85, 0.9) }) } }
  function revokePdf() { if (pdfUrl) URL.revokeObjectURL(pdfUrl); pdfUrl = '' }
</script>

<svelte:head><title>{t.title} | Print a Calendar</title><meta name="description" content={t.subtitle} /><link rel="canonical" href={`https://printacalendar.alon.one/${language}/`} />{#each availableLanguages as item}<link rel="alternate" hreflang={item[0]} href={`https://printacalendar.alon.one/${item[0]}/`} />{/each}<link rel="alternate" hreflang="x-default" href="https://printacalendar.alon.one/es/" /></svelte:head>

<a href="#main" class="skip-link">{t.skip}</a><header class:is-menu-open={menuOpen} class="site-header"><div class="page-shell header-inner"><a href={languageUrl(language)} class="brand"><span class="brand-mark">PC</span><strong>Print a Calendar</strong></a><button class="menu-toggle" type="button" aria-label={t.menuLabel} aria-expanded={menuOpen} on:click={() => menuOpen = !menuOpen}><span></span><span></span><span></span></button><div class="header-right"><nav><a href="#main" on:click={() => menuOpen = false}>{t.home}</a><a href="#wizard" on:click={() => { goToStep(0); menuOpen = false }}>{t.wizard}</a><a href="#preview" on:click={() => { goToStep(5); menuOpen = false }}>{t.previewNav}</a><button class="nav-button" type="button" on:click={() => { generatePdf(); menuOpen = false }}>{t.generateNav}</button></nav><div class="header-actions"><button class="theme-toggle" type="button" aria-label={t.themeLabel} aria-pressed={theme === 'dark'} on:click={toggleTheme}><span>{theme === 'dark' ? '🌙' : '☀️'}</span><span class="theme-toggle-text">{t.theme}</span></button><div class="language-switcher">{#each availableLanguages as item}<a class:active={language === item[0]} href={languageUrl(item[0])} hreflang={item[0]} on:click={() => rememberLanguage(item[0])}>{item[1]}</a>{/each}</div></div></div></div></header>

<main id="main" class="wizard-shell"><section class="hero"><span class="badge">{t.badge}</span><h1>{t.title}</h1><p>{t.subtitle}</p></section><section id="wizard" class="wizard-layout"><aside class="steps-panel">{#each steps as step, index}<button class:active={index === stepIndex} class:done={index < stepIndex} on:click={() => goToStep(index)}><span>{index + 1}</span><strong>{step.title}</strong></button>{/each}</aside><section class="wizard-card"><p class="step-kicker">{t.step} {stepIndex + 1} {t.of} {steps.length}</p><h2>{currentStep.title}</h2><p class="help">{currentStep.help}</p>{#if currentStep.key === 'date'}<div class="field-grid two"><label>{t.labels.startMonth}<select bind:value={startMonth}>{#each monthNames as name, index}<option value={index}>{name}</option>{/each}</select><small>{t.labels.startMonthHelp}</small></label><label>{t.labels.startYear}<input type="number" min="1900" max="2100" bind:value={startYear} /><small>{t.labels.startYearHelp}</small></label></div>{:else if currentStep.key === 'range'}<div class="choice-grid">{#each [1,3,6,12,18,24] as amount}<button class:selected={Number(totalMonths) === amount} on:click={() => totalMonths = amount}>{amount} {amount === 1 ? t.summary.month : t.summary.months}</button>{/each}</div><label class="range-field">{t.labels.custom}<input type="range" min="1" max="24" bind:value={totalMonths} /><strong>{totalMonths}</strong></label>{:else if currentStep.key === 'page'}<div class="field-grid four"><label>{t.labels.paper}<select bind:value={pageSize}><option>A4</option><option>A3</option><option>Letter</option></select><small>{t.labels.paperHelp}</small></label><label>{t.labels.orientation}<select bind:value={orientation}><option value="landscape">{t.labels.landscape}</option><option value="portrait">{t.labels.portrait}</option></select><small>{t.labels.orientationHelp}</small></label><label>{t.labels.monthsPerPage}<select bind:value={monthsPerPage}>{#each [1,2,3,4,6,8,9,12] as n}<option value={n}>{n}</option>{/each}</select><small>{t.labels.monthsPerPageHelp}</small></label><label>{t.labels.columns}<select bind:value={monthColumns}><option value="auto">{t.labels.auto}</option>{#each [1,2,3,4] as n}<option value={n}>{n}</option>{/each}</select><small>{t.labels.columnsHelp}</small></label></div>{:else if currentStep.key === 'content'}<div class="toggle-grid"><label><input type="checkbox" bind:checked={showHolidays} /> {t.labels.holidays}<small>{t.labels.holidaysHelp}</small></label>{#if showHolidays}<label>{t.labels.country}<select bind:value={country}>{#each countries as item}<option value={item[0]}>{item[1]}</option>{/each}</select></label><label>{t.labels.region}<select bind:value={region}>{#each availableRegions as item}<option value={item[0]}>{item[1]}</option>{/each}</select></label>{/if}<label><input type="checkbox" bind:checked={shadeWeekends} /> {t.labels.weekends}<small>{t.labels.weekendsHelp}</small></label><label><input type="checkbox" bind:checked={showWeekNumbers} /> {t.labels.weekNumbers}<small>{t.labels.weekNumbersHelp}</small></label><label><input type="checkbox" bind:checked={showEmptyDays} /> {t.labels.outsideDays}<small>{t.labels.outsideDaysHelp}</small></label><label><input type="checkbox" bind:checked={showNotes} /> {t.labels.notes}<small>{t.labels.notesHelp}</small></label></div>{:else if currentStep.key === 'style'}<div class="field-grid two"><label>{t.labels.daySize}<select bind:value={daySize}><option value="compact">{t.labels.compact}</option><option value="comfortable">{t.labels.comfortable}</option><option value="large">{t.labels.large}</option></select><small>{t.labels.daySizeHelp}</small></label><label>{t.labels.colorMode}<select bind:value={colorMode}><option value="color">{t.labels.color}</option><option value="grayscale">{t.labels.grayscale}</option></select><small>{t.labels.colorModeHelp}</small></label><label class="check"><input type="checkbox" bind:checked={roundedCells} /> {t.labels.rounded}</label><label class="check"><input type="checkbox" bind:checked={includeFooter} /> {t.labels.footer}</label></div>{:else}<div id="preview" class="summary-grid"><div><h3>{t.selectedOptions}</h3><dl>{#each selectedSummary as row}<div><dt>{row[0]}</dt><dd>{row[1]}</dd></div>{/each}</dl><div class="edit-actions">{#each steps.slice(0, 5) as step, index}<button on:click={() => goToStep(index)}>{t.labels.change} {index + 1}</button>{/each}</div></div><div><h3>{t.preview}</h3><div class="calendar-preview"><h4>{monthNames[calendarMonths[0].month]} {calendarMonths[0].year}</h4><div class="week-row">{#each weekNames as day}<strong>{day}</strong>{/each}</div><div class="days-row">{#each daysForMonth(calendarMonths[0].year, calendarMonths[0].month).slice(0, 42) as cell}<span class:muted={cell.muted} class:weekend={shadeWeekends && cell.weekend && !cell.muted}>{cell.day}</span>{/each}</div></div></div></div>{/if}{#if message}<p class="message">{message}</p>{/if}<div class="wizard-actions"><button class="secondary" on:click={previousStep} disabled={stepIndex === 0}>{t.back}</button>{#if stepIndex < steps.length - 1}<button class="primary" on:click={nextStep}>{t.next}</button>{:else}<button class="primary" on:click={generatePdf} disabled={isGenerating}>{isGenerating ? t.generating : t.generatePdf}</button>{/if}</div></section></section>{#if pdfUrl}<section class="result-panel"><div><h2>{t.readyTitle}</h2><p>{t.readyText}</p></div><div class="result-actions"><a class="primary link" href={pdfUrl} download="calendar-printacalendar.pdf">{t.download}</a><button class="secondary" on:click={() => window.open(pdfUrl, '_blank')}>{t.openPreview}</button></div><iframe title={t.preview} src={pdfUrl}></iframe></section>{/if}</main>

<style>
:global(:root){color-scheme:light;--bg:#f6f6fa;--surface:#fff;--soft:#fbfcff;--raised:rgba(255,255,255,.96);--text:#2b2d38;--muted:#636779;--softText:#787d8d;--border:#dddfea;--strong:#cfd3df;--primary:#f0523d;--hover:#dd3427;--primarySoft:#ffe4dd;--secondary:#b9231b;--blur:rgba(255,255,255,.94);--shadow:0 18px 46px rgba(27,31,45,.1);--brandShadow:0 18px 40px rgba(240,82,61,.26);font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}:global(html[data-theme='dark']){color-scheme:dark;--bg:#020617;--surface:#0f172a;--soft:#111827;--raised:#1e293b;--text:#f8fafc;--muted:#cbd5e1;--softText:#94a3b8;--border:#1e293b;--strong:#334155;--primary:#fb923c;--hover:#fdba74;--primarySoft:rgb(249 115 22/.18);--secondary:#f87171;--blur:rgba(15,23,42,.96);--shadow:0 16px 40px rgb(0 0 0/.45);--brandShadow:0 18px 40px rgb(249 115 22/.18)}:global(*){box-sizing:border-box}:global(body){margin:0;min-height:100vh;background:radial-gradient(circle at -8% 38%,color-mix(in srgb,var(--primary) 9%,transparent),transparent 24rem),radial-gradient(circle at 105% 22%,color-mix(in srgb,var(--primary) 9%,transparent),transparent 25rem),linear-gradient(180deg,color-mix(in srgb,var(--surface) 68%,var(--bg)) 0%,var(--bg) 44%,color-mix(in srgb,var(--bg) 92%,#e5e7eb) 100%);color:var(--text);font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;overflow-x:hidden}:global(button),:global(input),:global(select){font:inherit}.skip-link{position:fixed;left:1rem;top:1rem;z-index:100;transform:translateY(-140%);padding:.75rem 1rem;border-radius:1rem;background:var(--primary);color:white;font-weight:900}.skip-link:focus{transform:none}.page-shell{width:min(92.5rem,calc(100% - clamp(2rem,6vw,4rem)));margin:auto}.site-header{position:sticky;top:0;z-index:50}.site-header:before{content:'';position:absolute;inset:0;z-index:-1;background:color-mix(in srgb,var(--surface) 94%,transparent);border-bottom:1px solid var(--border);backdrop-filter:blur(18px)}.header-inner{min-height:4.6rem;display:grid;grid-template-columns:auto 1fr;align-items:center;gap:1.5rem}.brand{display:flex;align-items:center;gap:.7rem;color:var(--text);font-weight:950;text-decoration:none;letter-spacing:-.055em}.brand-mark{display:grid;place-items:center;width:2.55rem;height:2.55rem;border-radius:.85rem;background:linear-gradient(135deg,var(--primary),var(--secondary));color:white;font-size:.72rem;font-weight:950;box-shadow:var(--brandShadow)}.brand strong{font-size:clamp(1.15rem,1.6vw,1.45rem)}.menu-toggle{display:none;width:2.85rem;height:2.85rem;align-items:center;justify-content:center;flex-direction:column;gap:.28rem;border:1px solid var(--border);border-radius:1rem;background:var(--surface);color:var(--text)}.menu-toggle span{width:1.25rem;height:2px;background:currentColor;border-radius:99px;transition:.2s}.is-menu-open .menu-toggle span:nth-child(1){transform:translateY(6px) rotate(45deg)}.is-menu-open .menu-toggle span:nth-child(2){opacity:0}.is-menu-open .menu-toggle span:nth-child(3){transform:translateY(-6px) rotate(-45deg)}.header-right,.header-actions,.language-switcher,nav{display:flex;align-items:center}.header-right{justify-content:flex-end;gap:1rem}nav{gap:.35rem}nav a,.nav-button,.language-switcher a{display:inline-flex;align-items:center;min-height:2.8rem;padding:0 .75rem;border:0;border-radius:99px;background:transparent;color:var(--text);font-size:.96rem;font-weight:850;text-decoration:none;cursor:pointer}.header-actions{gap:.45rem}.theme-toggle{min-width:2.55rem;height:2.55rem;border:0;border-radius:.7rem;background:transparent;color:var(--text);cursor:pointer}.theme-toggle-text{display:none}.language-switcher a{min-height:2.25rem;color:var(--muted);font-size:.75rem}.language-switcher a.active{background:var(--text);color:var(--surface)}.wizard-shell{width:min(1180px,calc(100% - 24px));margin:auto;padding:32px 0 56px}.hero{padding:clamp(3rem,6vw,5.2rem) 0 2rem;text-align:center;display:grid;justify-items:center;gap:1rem}.badge{padding:.55rem .8